{
  my ($value) = @_;
  my $integer = int($value);
  my $fraction = $value - $integer;
  if ($fraction > 0.5) {
    return $integer + 1;
  } elsif ($fraction < -0.5) {
    return $integer - 1;
  } else {
    return $integer;
  }
