 * xs[0] + xs[1] * x + xs[2] * x^2 + ....
 *  Return integral of this polynomial in the same form.
 * >>> integral([3, 1, 2, 4, 5])
 * [1, 1/2, 1/3, 1/4, 1/5]
 * >>> integral([1, 2, 3])
 * [1/2, 2/3, 3/4]
 *
 */
function integral(xs) {
  let n = xs.length;
  let ys = new Array(n + 1);
  ys[0] = 0;
  for (let i = 0; i < n; i++) {
    ys[i + 1] = xs[i] / (i + 1);
  }
  return ys;
}

