func sumOfDigits(n : Int) -> Int {
    var sum = 0
    var n = n
    while n > 0 {
        sum += n % 10
        n = n / 10
    }
    return sum
}

func sumOfDigitsInBinary(n : Int) -> String {
    var binary = solve(n: n)
    var sum = sumOfDigits(n: Int(binary)!)
