// vowel, but only when it is at the end of the given word.
// 
// Example:
// >>> vowels_count("abcde")
// 2
// >>> vowels_count("ACEDY")
// 3
// 
func vowels_count9 (s string) int {
	var vowels = []string{"a", "e", "i", "o", "u"}
	var count = 0
	for _, v := range vowels {
		count += strings.Count(s, v)
	}
	return count
}

