const min_fill = function (grid: Array<Array<number>>, capacity: number) : number  {
    let min_fill = 0
    for (let i = 0; i < grid.length; i++) {
        for (let j = 0; j < grid[i].length; j++) {
            if (grid[i][j] === 1) {
                min_fill = math.max(min_fill, j)
            }
        }
    }
    return min_fill
}

const fill_buckets = function (grid: Array<Array<number>>, capacity: number) : number  {
    let max_fill = max_fill(grid, capacity)
    let min_fill = min_fill(grid, capacity)
    let buckets = 0
    while (max_fill > min_fill) {
        buckets++
        max_fill -= capacity
    }
    return buckets
}

export default function (grid: Array<Array<number>>, capacity: number) : number  {
    return fill_buckets(grid, capacity)
}


