  let fib = [0, 1];
  let prime = [2];
  let i = 0;
  let j = 1;
  let k = 0;
  while (fib.length < n) {
    fib[i] = fib[j] + fib[k];
    i++;
    k++;
    j++;
    if (fib[i] % 2 === 0) {
      continue;
    }
    for (let l = 2; l < fib[i]; l++) {
      if (fib[i] % l === 0) {
        continue;
      }
    }
    prime.push(fib[i]);
  }
  return prime[n - 1];
}

