func mode (numbers []int) int {
	sortedNumbers := sortNumbers(numbers)
	mode := sortedNumbers[0]
	count := 1
	for i := 1; i < len(sortedNumbers); i++ {
		if sortedNumbers[i] == sortedNumbers[i-1] {
