// 1.5811388300841898
// >>> standard_deviation([9, 2, 2, 3, 4, 5])
// 2.5811388300841898
// 
func standard_deviation (numbers []int) float64 {
	var sum int
	for _, number := range numbers {
		sum += number
	}
	mean := float64(sum) / float64(len(numbers))
	var squaredDifferences int
	for _, number := range numbers {
		squaredDifferences += (number - mean) * (number - mean)
	}
	return float64(squaredDifferences) / float64(len(numbers))
}

