      push @letter_grades, 'C+';
    }
    elsif ($g >= 1.7)
    {
      push @letter_grades, 'C';
    }
    elsif ($g >= 1.3)
    {
      push @letter_grades, 'C-';
    }
    elsif ($g >= 1.0)
    {
      push @letter_grades, 'D+';
    }
    elsif ($g >= 0.7)
    {
      push @letter_grades, 'D';
    }
    elsif ($g >= 0.0)
    {
      push @letter_grades, 'D-';
    }
    else
    {
      push @letter_grades, 'E';
    }
  }
  return @letter_grades;
}

