    public static boolean isPalindrome(int n) {
        int temp = n;
        int reverse = 0;
        while (temp != 0) {
            int lastDigit = temp % 10;
            reverse = reverse * 10 + lastDigit;
            temp = temp / 10;
        }
        return n == reverse;
    }

