public static string RemoveVowels (string input) 
{ 
    string result = "";
    foreach (char c in input)
    {
        if (!c.Equals('a') && !c.Equals('e') && !c.Equals('i') && !c.Equals('o') && !c.Equals('u'))
        {
            result += c;
        }
    }
    return result;
}

