    private static int fill(int[][] dp, int i, int j, int capacity) {
        int rows = dp.length;
        int cols = dp[0].length;
        int[][] visited = new int[rows][cols];
        int maxFill = 0;
        Queue<int[]> q = new LinkedList<>();
        q.add(new int[]{i, j});
        visited[i][j] = 1;
        while (!q.isEmpty()) {
            int[] curr = q.poll();
            int x = curr[0];
            int y = curr[1];
            if (dp[x][y] == 1) {
                maxFill++;
            }
            if (x - 1 >= 0 && visited[x - 1][y] == 0 && dp[x - 1][y] == 1) {
                q.add(new int[]{x - 1, y});
                visited[x - 1][y] = 1;
            }
            if (x + 1 < rows && visited[x + 1][y] == 0 && dp[x + 1][y] == 1) {
                q.add(new int[]{x + 1, y});
                visited[x + 1][y] = 1;
            }
            if (y - 1 >= 0 && visited[x][y - 1] == 0 && dp[x][y - 1] == 1) {
                q.add(new int[]{x, y - 1});
                visited[x][y - 1] = 1;
            }
            if (y + 1 < cols && visited[x][y + 1] == 0 && dp[x][y + 1] == 1) {
                q.add(new int[]{x, y + 1});
                visited[x][y + 1] = 1;
            }
        }
        return maxFill;
    }

