func isPalindrome (n int) bool {
	s := reflect.ValueOf(n).String()
	if s == reverse(s) {
		return true
	}
	return false
}

func reverse (s string) string {
	var r string
	for i := len(s) - 1; i >= 0; i-- {
		r += string(s[i])
	}
	return r
}

func isEven (n int) bool {
	if n % 2 == 0 {
		return true
	}
	return false
}

