		case grade.(float64) >= 3.3:
			letter_grades = append(letter_grades, "A-")
		case grade.(float64) >= 3.0:
			letter_grades = append(letter_grades, "B+")
		case grade.(float64) >= 2.7:
			letter_grades = append(letter_grades, "B")
		case grade.(float64) >= 2.3:
			letter_grades = append(letter_grades, "B-")
		case grade.(float64) >= 2.0:
			letter_grades = append(letter_grades, "C+")
		case grade.(float64) >= 1.7:
			letter_grades = append(letter_grades, "C")
		case grade.(float64) >= 1.3:
			letter_grades = append(letter_grades, "C-")
		case grade.(float64) >= 1.0:
			letter_grades = append(letter_grades, "D+")
		case grade.(float64) >= 0.7:
			letter_grades = append(letter_grades, "D")
		case grade.(float64) >= 0.0:
			letter_grades = append(letter_grades, "D-")
		default:
			letter_grades = append(letter_grades, "E")
		}
	}
	return letter_grades
}

