/// brazilian_factorial(n) = n! * (n-1)! * (n-2)! * ... * 1!
/// where n > 0
/// 
/// For example:
/// >>> SpecialFactorial(4)
/// 288
/// 
/// The function will receive an integer as input and should return the special
/// factorial of this integer.
/// 
/// </summary>
public static int SpecialFactorial3 (int n) 
{ 
    int result = 1;
    for (int i = n; i > 0; i--)
    {
        result *= i;
    }
    return result;
}

